/*
  # Comprehensive Onboarding Email for Registration (v2)

  1. Changes
    - Replaces the German "registration" email template with a full onboarding email
    - Sections: Hero, Why it pays off, Step 1 (Objekt with how-to), Step 2 (Einheit with
      explanation box), Step 3 (Mietverhaeltnis with benefits), Testimonials from marketing
      site, CSV/Excel import hint, Startup checklist, Contact/Questions block, Footer
    - Header and Footer preserved from existing template structure
    - Template variables preserved: {{userName}}, {{dashboard_link}}, {{user_email}}

  2. Design Direction
    - Consistent with rentably marketing website: #3c8af7 primary, #EEF4FF accents,
      #1E1E24 dark text, #f8fafc card backgrounds, 8px spacing system
    - Numbered step cards, benefit checklists, testimonial cards with stars,
      visual checklist with checkboxes, info boxes for explanations and tips

  3. Security
    - No schema changes, data-only update on existing row
*/

DO $$
DECLARE
  v_html text;
  v_text text;
BEGIN

v_html := E'<!DOCTYPE html>\n<html lang="de">\n<head>\n<meta charset="utf-8">\n<meta name="viewport" content="width=device-width, initial-scale=1.0">\n<meta http-equiv="X-UA-Compatible" content="IE=edge">\n<title>Willkommen bei rentably</title>\n</head>\n<body style="margin: 0; padding: 0; background-color: #f5f5f5; font-family: \'Manrope\', Arial, Helvetica, sans-serif; -webkit-text-size-adjust: none; text-size-adjust: none;">\n<table width="100%" border="0" cellpadding="0" cellspacing="0" style="background-color: #f5f5f5;">\n<tr><td align="center" style="padding: 32px 16px;">\n<table width="600" border="0" cellpadding="0" cellspacing="0" style="max-width: 600px; width: 100%; background-color: #ffffff; border-radius: 8px; overflow: hidden;">\n\n<!-- ============ HEADER (unchanged) ============ -->\n<tr><td style="padding: 28px 32px 20px; text-align: center; border-bottom: 1px solid #eee;">\n<a href="https://rentab.ly" target="_blank" style="display: inline-block;">\n<img src="https://6f36f82794.imgdist.com/pub/bfra/2bnm3c1v/dzm/8g5/nzj/rentably-logo.svg" alt="rentably" width="180" style="display: block; height: auto; border: 0;" />\n</a>\n</td></tr>\n\n<!-- ============ 1. HERO ============ -->\n<tr><td style="padding: 36px 32px 0;">\n<h1 style="margin: 0 0 16px; color: #1E1E24; font-size: 22px; font-weight: 700; line-height: 1.35;">Willkommen bei rentably</h1>\n<p style="margin: 0 0 8px; color: #555; font-size: 14px; line-height: 1.65;">Hallo <strong style="color: #1E1E24;">{{userName}}</strong>,</p>\n<p style="margin: 0; color: #555; font-size: 14px; line-height: 1.65;">sch&ouml;n, dass Sie hier sind. Ihr 30-t&auml;giger Pro-Test ist jetzt aktiv &ndash; Sie k&ouml;nnen ab sofort alle Funktionen nutzen. Damit der Einstieg leicht f&auml;llt, zeigen wir Ihnen die drei wichtigsten Schritte f&uuml;r den Start.</p>\n</td></tr>\n\n<!-- ============ 2. WARUM LOHNT SICH DAS? ============ -->\n<tr><td style="padding: 28px 32px 0;">\n<table width="100%" border="0" cellpadding="0" cellspacing="0" style="background-color: #f8fafc; border-radius: 8px; border: 1px solid #eef2f6;">\n<tr><td style="padding: 22px 20px;">\n<p style="margin: 0 0 14px; color: #1E1E24; font-size: 15px; font-weight: 700; line-height: 1.3;">Warum lohnt sich der Einstieg?</p>\n<table width="100%" border="0" cellpadding="0" cellspacing="0">\n<tr><td style="padding: 0 0 8px;">\n<table border="0" cellpadding="0" cellspacing="0"><tr>\n<td width="24" valign="top" style="padding-top: 1px; color: #3c8af7; font-size: 14px;">&#10003;</td>\n<td style="color: #555; font-size: 13px; line-height: 1.55;"><strong style="color: #1E1E24;">Kompletter &Uuml;berblick</strong> &ndash; Objekte, Einheiten und Mietvertr&auml;ge an einem Ort</td>\n</tr></table>\n</td></tr>\n<tr><td style="padding: 0 0 8px;">\n<table border="0" cellpadding="0" cellspacing="0"><tr>\n<td width="24" valign="top" style="padding-top: 1px; color: #3c8af7; font-size: 14px;">&#10003;</td>\n<td style="color: #555; font-size: 13px; line-height: 1.55;"><strong style="color: #1E1E24;">Mietkonten im Blick</strong> &ndash; Zahlungseing&auml;nge automatisch erfassen, kein manuelles Nachhalten mehr</td>\n</tr></table>\n</td></tr>\n<tr><td style="padding: 0 0 8px;">\n<table border="0" cellpadding="0" cellspacing="0"><tr>\n<td width="24" valign="top" style="padding-top: 1px; color: #3c8af7; font-size: 14px;">&#10003;</td>\n<td style="color: #555; font-size: 13px; line-height: 1.55;"><strong style="color: #1E1E24;">Alles digital</strong> &ndash; Dokumente, Kommunikation und Abrechnungen zentral und jederzeit abrufbar</td>\n</tr></table>\n</td></tr>\n<tr><td style="padding: 0;">\n<table border="0" cellpadding="0" cellspacing="0"><tr>\n<td width="24" valign="top" style="padding-top: 1px; color: #3c8af7; font-size: 14px;">&#10003;</td>\n<td style="color: #555; font-size: 13px; line-height: 1.55;"><strong style="color: #1E1E24;">Weniger Aufwand</strong> &ndash; Betriebskostenabrechnungen in Minuten statt Stunden erstellen</td>\n</tr></table>\n</td></tr>\n</table>\n</td></tr>\n</table>\n</td></tr>\n\n<!-- ============ STEPS SECTION HEADER ============ -->\n<tr><td style="padding: 32px 32px 0; text-align: center;">\n<p style="margin: 0 0 4px; color: #3c8af7; font-size: 11px; font-weight: 700; text-transform: uppercase; letter-spacing: 1.5px;">Ihre ersten 3 Schritte</p>\n<p style="margin: 0; color: #888; font-size: 13px; line-height: 1.5;">So richten Sie rentably in wenigen Minuten ein.</p>\n</td></tr>\n\n<!-- ============ 3. SCHRITT 1: OBJEKT ============ -->\n<tr><td style="padding: 20px 32px 0;">\n<table width="100%" border="0" cellpadding="0" cellspacing="0" style="background-color: #f8fafc; border-radius: 8px; border: 1px solid #eef2f6;">\n<tr><td style="padding: 22px 20px;">\n<table border="0" cellpadding="0" cellspacing="0" width="100%"><tr>\n<td width="44" valign="top">\n<div style="width: 34px; height: 34px; border-radius: 50%; background-color: #EEF4FF; border: 1px solid #DDE7FF; text-align: center; line-height: 34px; font-size: 14px; font-weight: 700; color: #3c8af7;">1</div>\n</td>\n<td valign="top">\n<p style="margin: 0 0 6px; color: #1E1E24; font-size: 15px; font-weight: 700; line-height: 1.3;">Objekt anlegen</p>\n<p style="margin: 0 0 14px; color: #666; font-size: 13px; line-height: 1.6;">Erstellen Sie Ihr erstes Objekt in rentably und hinterlegen Sie die wichtigsten Daten. So haben Sie immer einen vollst&auml;ndigen &Uuml;berblick &uuml;ber Ihre Immobilien &ndash; egal ob Mehrfamilienhaus, Eigentumswohnung oder Gewerbeeinheit.</p>\n<p style="margin: 0 0 6px; color: #1E1E24; font-size: 12px; font-weight: 600;">So funktioniert&#39;s:</p>\n<table border="0" cellpadding="0" cellspacing="0">\n<tr><td style="padding: 0 0 3px; color: #666; font-size: 12px; line-height: 1.5;"><span style="color: #3c8af7; font-weight: 600;">1.</span>&nbsp; Melden Sie sich bei rentably an</td></tr>\n<tr><td style="padding: 0 0 3px; color: #666; font-size: 12px; line-height: 1.5;"><span style="color: #3c8af7; font-weight: 600;">2.</span>&nbsp; Gehen Sie zu &bdquo;Objekte&ldquo; und klicken Sie auf &bdquo;Objekt hinzuf&uuml;gen&ldquo;</td></tr>\n<tr><td style="padding: 0; color: #666; font-size: 12px; line-height: 1.5;"><span style="color: #3c8af7; font-weight: 600;">3.</span>&nbsp; W&auml;hlen Sie den Objekttyp und geben Sie die Adresse ein</td></tr>\n</table>\n</td>\n</tr></table>\n</td></tr>\n</table>\n</td></tr>\n\n<!-- ============ 4. SCHRITT 2: EINHEIT ============ -->\n<tr><td style="padding: 12px 32px 0;">\n<table width="100%" border="0" cellpadding="0" cellspacing="0" style="background-color: #f8fafc; border-radius: 8px; border: 1px solid #eef2f6;">\n<tr><td style="padding: 22px 20px;">\n<table border="0" cellpadding="0" cellspacing="0" width="100%"><tr>\n<td width="44" valign="top">\n<div style="width: 34px; height: 34px; border-radius: 50%; background-color: #EEF4FF; border: 1px solid #DDE7FF; text-align: center; line-height: 34px; font-size: 14px; font-weight: 700; color: #3c8af7;">2</div>\n</td>\n<td valign="top">\n<p style="margin: 0 0 6px; color: #1E1E24; font-size: 15px; font-weight: 700; line-height: 1.3;">Einheiten hinzuf&uuml;gen</p>\n<p style="margin: 0 0 14px; color: #666; font-size: 13px; line-height: 1.6;">Nachdem Ihr Objekt angelegt ist, f&uuml;gen Sie die zugeh&ouml;rigen Einheiten hinzu. Damit stellen Sie sicher, dass jeder Einheit sp&auml;ter ein Mietverh&auml;ltnis und die richtigen Buchungen zugeordnet werden.</p>\n<p style="margin: 0 0 6px; color: #1E1E24; font-size: 12px; font-weight: 600;">Warum ist das wichtig?</p>\n<table border="0" cellpadding="0" cellspacing="0">\n<tr><td style="padding: 0 0 3px; color: #666; font-size: 12px; line-height: 1.5;"><span style="color: #3c8af7;">&#10003;</span>&nbsp; Mietverh&auml;ltnisse und Zahlungen korrekt zuordnen</td></tr>\n<tr><td style="padding: 0 0 3px; color: #666; font-size: 12px; line-height: 1.5;"><span style="color: #3c8af7;">&#10003;</span>&nbsp; Voraussetzung f&uuml;r die Nebenkostenabrechnung</td></tr>\n<tr><td style="padding: 0 0 12px; color: #666; font-size: 12px; line-height: 1.5;"><span style="color: #3c8af7;">&#10003;</span>&nbsp; &Uuml;bersicht &uuml;ber vermietete Einheiten und Leerstand</td></tr>\n</table>\n<table width="100%" border="0" cellpadding="0" cellspacing="0" style="background-color: #ffffff; border-radius: 6px; border: 1px solid #e5e7eb;">\n<tr><td style="padding: 12px 14px;">\n<p style="margin: 0 0 4px; color: #1E1E24; font-size: 12px; font-weight: 600;">Was ist eine Einheit?</p>\n<p style="margin: 0; color: #888; font-size: 12px; line-height: 1.55;">Eine Einheit ist z.&thinsp;B. eine Wohnung, eine Garage / ein Stellplatz oder eine Gewerbefl&auml;che. Alles, was einen eigenen Mietvertrag erh&auml;lt, kann eine Einheit sein. <strong style="color: #666;">Beispiel:</strong> Ein Objekt mit 10 Wohnungen, 3 Stellpl&auml;tzen und einem Ladenlokal enth&auml;lt insgesamt 14 Einheiten.</p>\n</td></tr>\n</table>\n</td>\n</tr></table>\n</td></tr>\n</table>\n</td></tr>\n\n<!-- ============ 5. SCHRITT 3: MIETVERHAELTNIS ============ -->\n<tr><td style="padding: 12px 32px 0;">\n<table width="100%" border="0" cellpadding="0" cellspacing="0" style="background-color: #f8fafc; border-radius: 8px; border: 1px solid #eef2f6;">\n<tr><td style="padding: 22px 20px;">\n<table border="0" cellpadding="0" cellspacing="0" width="100%"><tr>\n<td width="44" valign="top">\n<div style="width: 34px; height: 34px; border-radius: 50%; background-color: #EEF4FF; border: 1px solid #DDE7FF; text-align: center; line-height: 34px; font-size: 14px; font-weight: 700; color: #3c8af7;">3</div>\n</td>\n<td valign="top">\n<p style="margin: 0 0 6px; color: #1E1E24; font-size: 15px; font-weight: 700; line-height: 1.3;">Mietverh&auml;ltnis erfassen</p>\n<p style="margin: 0 0 14px; color: #666; font-size: 13px; line-height: 1.6;">Jetzt legen Sie Ihre Mietverh&auml;ltnisse direkt in den passenden Einheiten an. So haben Sie Mietzahlungen, Vertr&auml;ge und Mieterdaten vollst&auml;ndig und &uuml;bersichtlich an einem Ort.</p>\n<p style="margin: 0 0 6px; color: #1E1E24; font-size: 12px; font-weight: 600;">Vorteile der digitalen Mietverwaltung:</p>\n<table border="0" cellpadding="0" cellspacing="0">\n<tr><td style="padding: 0 0 3px; color: #666; font-size: 12px; line-height: 1.5;"><span style="color: #3c8af7;">&#10003;</span>&nbsp; Automatische Mietbuchungen und Zahlungserinnerungen</td></tr>\n<tr><td style="padding: 0 0 3px; color: #666; font-size: 12px; line-height: 1.5;"><span style="color: #3c8af7;">&#10003;</span>&nbsp; Mieterdaten und Dokumente zentral gespeichert</td></tr>\n<tr><td style="padding: 0; color: #666; font-size: 12px; line-height: 1.5;"><span style="color: #3c8af7;">&#10003;</span>&nbsp; &Uuml;bersicht &uuml;ber alle aktiven Mietverh&auml;ltnisse</td></tr>\n</table>\n</td>\n</tr></table>\n</td></tr>\n</table>\n</td></tr>\n\n<!-- ============ PRIMARY CTA ============ -->\n<tr><td style="padding: 28px 32px 0; text-align: center;">\n<a href="{{dashboard_link}}" style="display: inline-block; background-color: #3c8af7; color: #ffffff; text-decoration: none; padding: 13px 40px; border-radius: 8px; font-size: 15px; font-weight: 700; letter-spacing: 0.01em;">Jetzt loslegen</a>\n</td></tr>\n\n<!-- ============ 6. TESTIMONIALS ============ -->\n<tr><td style="padding: 36px 32px 0;">\n<table width="100%" border="0" cellpadding="0" cellspacing="0" style="border-top: 1px solid #eee;">\n<tr><td style="padding: 28px 0 0; text-align: center;">\n<p style="margin: 0 0 4px; color: #1E1E24; font-size: 15px; font-weight: 700;">Das sagen unsere Nutzer</p>\n<p style="margin: 0 0 20px; color: #888; font-size: 12px;">Zufriedene Vermieter verwalten ihre Immobilien mit rentably.</p>\n</td></tr>\n</table>\n<table width="100%" border="0" cellpadding="0" cellspacing="0" style="background-color: #f8fafc; border-radius: 8px; border: 1px solid #eef2f6; margin-bottom: 10px;">\n<tr><td style="padding: 18px 18px 14px;">\n<p style="margin: 0 0 2px; color: #f59e0b; font-size: 12px; letter-spacing: 1px;">&#9733;&#9733;&#9733;&#9733;&#9733;</p>\n<p style="margin: 0 0 10px; color: #555; font-size: 13px; line-height: 1.55; font-style: italic;">&bdquo;Seit ich rentably nutze, habe ich endlich den &Uuml;berblick &uuml;ber alle Mietverh&auml;ltnisse. Die Betriebskostenabrechnung dauert keine Stunden mehr, sondern Minuten.&ldquo;</p>\n<p style="margin: 0; color: #1E1E24; font-size: 12px; font-weight: 600;">Thomas M. <span style="color: #999; font-weight: 400;">&ndash; Vermieter, 4 Wohnungen</span></p>\n</td></tr>\n</table>\n<table width="100%" border="0" cellpadding="0" cellspacing="0" style="background-color: #f8fafc; border-radius: 8px; border: 1px solid #eef2f6;">\n<tr><td style="padding: 18px 18px 14px;">\n<p style="margin: 0 0 2px; color: #f59e0b; font-size: 12px; letter-spacing: 1px;">&#9733;&#9733;&#9733;&#9733;&#9733;</p>\n<p style="margin: 0 0 10px; color: #555; font-size: 13px; line-height: 1.55; font-style: italic;">&bdquo;Die Struktur mit Einheiten, Mietern und Vertr&auml;gen bildet unseren Arbeitsalltag perfekt ab. Endlich ein Tool, das f&uuml;r professionelle Verwalter gemacht ist.&ldquo;</p>\n<p style="margin: 0; color: #1E1E24; font-size: 12px; font-weight: 600;">Markus F. <span style="color: #999; font-weight: 400;">&ndash; Gesch&auml;ftsf&uuml;hrer, WEG-Verwaltung</span></p>\n</td></tr>\n</table>\n</td></tr>\n\n<!-- ============ 7. IMPORT HINWEIS ============ -->\n<tr><td style="padding: 28px 32px 0;">\n<table width="100%" border="0" cellpadding="0" cellspacing="0" style="border-top: 1px solid #eee;">\n<tr><td style="padding: 24px 0 0;">\n<table width="100%" border="0" cellpadding="0" cellspacing="0" style="background-color: #f8fafc; border-radius: 8px; border: 1px solid #eef2f6;">\n<tr><td style="padding: 20px;">\n<p style="margin: 0 0 6px; color: #1E1E24; font-size: 14px; font-weight: 700; line-height: 1.3;">Schnell Objekte &amp; Einheiten importieren</p>\n<p style="margin: 0 0 10px; color: #666; font-size: 13px; line-height: 1.6;">Je schneller Ihre Daten in rentably hinterlegt sind, desto effizienter wird Ihre Verwaltung.</p>\n<table border="0" cellpadding="0" cellspacing="0" style="background-color: #ffffff; border-radius: 6px; border: 1px solid #e5e7eb; width: 100%;">\n<tr><td style="padding: 10px 14px;">\n<p style="margin: 0; color: #888; font-size: 12px; line-height: 1.55;"><strong style="color: #1E1E24;">Tipp:</strong> Falls Sie bereits bestehende Daten haben, k&ouml;nnen Sie diese einfach per <strong style="color: #1E1E24;">CSV- oder Excel-Upload</strong> importieren &ndash; kein manuelles Eintippen n&ouml;tig.</p>\n</td></tr>\n</table>\n</td></tr>\n</table>\n</td></tr>\n</table>\n</td></tr>\n\n<!-- ============ 8. CHECKLISTE ============ -->\n<tr><td style="padding: 28px 32px 0;">\n<table width="100%" border="0" cellpadding="0" cellspacing="0" style="border-top: 1px solid #eee;">\n<tr><td style="padding: 24px 0 0;">\n<p style="margin: 0 0 16px; color: #1E1E24; font-size: 15px; font-weight: 700; line-height: 1.3;">Ihre Checkliste f&uuml;r den Start</p>\n<table width="100%" border="0" cellpadding="0" cellspacing="0">\n<tr><td style="padding: 0 0 6px;"><table border="0" cellpadding="0" cellspacing="0"><tr>\n<td width="22" valign="top" style="padding-top: 1px; color: #22c55e; font-size: 14px;">&#10003;</td>\n<td style="color: #999; font-size: 13px; line-height: 1.4; text-decoration: line-through;">Konto erstellt</td>\n</tr></table></td></tr>\n<tr><td style="padding: 0 0 6px;"><table border="0" cellpadding="0" cellspacing="0"><tr>\n<td width="22" valign="top" style="padding-top: 2px;"><div style="width: 14px; height: 14px; border-radius: 3px; border: 1.5px solid #ccc;"></div></td>\n<td style="color: #555; font-size: 13px; line-height: 1.4;"><strong style="color:#1E1E24;">Erstes Objekt anlegen</strong> <span style="color: #999;">&ndash; Grundlage f&uuml;r Ihr Immobilienmanagement</span></td>\n</tr></table></td></tr>\n<tr><td style="padding: 0 0 6px;"><table border="0" cellpadding="0" cellspacing="0"><tr>\n<td width="22" valign="top" style="padding-top: 2px;"><div style="width: 14px; height: 14px; border-radius: 3px; border: 1.5px solid #ccc;"></div></td>\n<td style="color: #555; font-size: 13px; line-height: 1.4;"><strong style="color:#1E1E24;">Einheit anlegen</strong> <span style="color: #999;">&ndash; Wohnung, Garage oder Gewerbe</span></td>\n</tr></table></td></tr>\n<tr><td style="padding: 0 0 6px;"><table border="0" cellpadding="0" cellspacing="0"><tr>\n<td width="22" valign="top" style="padding-top: 2px;"><div style="width: 14px; height: 14px; border-radius: 3px; border: 1.5px solid #ccc;"></div></td>\n<td style="color: #555; font-size: 13px; line-height: 1.4;"><strong style="color:#1E1E24;">Mietverh&auml;ltnis erfassen</strong> <span style="color: #999;">&ndash; Ausgangspunkt f&uuml;r Ihre Mietverwaltung</span></td>\n</tr></table></td></tr>\n<tr><td style="padding: 0 0 6px;"><table border="0" cellpadding="0" cellspacing="0"><tr>\n<td width="22" valign="top" style="padding-top: 2px;"><div style="width: 14px; height: 14px; border-radius: 3px; border: 1.5px solid #ccc;"></div></td>\n<td style="color: #555; font-size: 13px; line-height: 1.4;"><strong style="color:#1E1E24;">Bankkonto verkn&uuml;pfen</strong> <span style="color: #999;">&ndash; automatische Mieteingangskontrolle</span></td>\n</tr></table></td></tr>\n<tr><td style="padding: 0 0 6px;"><table border="0" cellpadding="0" cellspacing="0"><tr>\n<td width="22" valign="top" style="padding-top: 2px;"><div style="width: 14px; height: 14px; border-radius: 3px; border: 1.5px solid #ccc;"></div></td>\n<td style="color: #555; font-size: 13px; line-height: 1.4;"><strong style="color:#1E1E24;">Finanzen auswerten</strong> <span style="color: #999;">&ndash; Miet- und Objektberichte auf einen Blick</span></td>\n</tr></table></td></tr>\n<tr><td style="padding: 0 0 6px;"><table border="0" cellpadding="0" cellspacing="0"><tr>\n<td width="22" valign="top" style="padding-top: 2px;"><div style="width: 14px; height: 14px; border-radius: 3px; border: 1.5px solid #ccc;"></div></td>\n<td style="color: #555; font-size: 13px; line-height: 1.4;"><strong style="color:#1E1E24;">Nebenkostenabrechnung erstellen</strong> <span style="color: #999;">&ndash; mit nur wenigen Klicks</span></td>\n</tr></table></td></tr>\n<tr><td style="padding: 0 0 6px;"><table border="0" cellpadding="0" cellspacing="0"><tr>\n<td width="22" valign="top" style="padding-top: 2px;"><div style="width: 14px; height: 14px; border-radius: 3px; border: 1.5px solid #ccc;"></div></td>\n<td style="color: #555; font-size: 13px; line-height: 1.4;"><strong style="color:#1E1E24;">Dokumente digital speichern</strong> <span style="color: #999;">&ndash; kein Papierchaos mehr</span></td>\n</tr></table></td></tr>\n</table>\n</td></tr>\n</table>\n</td></tr>\n\n<!-- ============ TRIAL NOTE ============ -->\n<tr><td style="padding: 24px 32px 0; text-align: center;">\n<p style="margin: 0; color: #888; font-size: 13px; line-height: 1.6;">W&auml;hrend Ihrer 30-t&auml;gigen Testphase nutzen Sie rentably im vollen Pro-Umfang und lernen alle Funktionen direkt in der Praxis kennen.</p>\n</td></tr>\n\n<!-- ============ SECOND CTA ============ -->\n<tr><td style="padding: 24px 32px 0; text-align: center;">\n<a href="{{dashboard_link}}" style="display: inline-block; background-color: #3c8af7; color: #ffffff; text-decoration: none; padding: 13px 40px; border-radius: 8px; font-size: 15px; font-weight: 700; letter-spacing: 0.01em;">Jetzt Verwaltung starten</a>\n</td></tr>\n\n<!-- ============ 9. NOCH FRAGEN? ============ -->\n<tr><td style="padding: 32px 32px 0;">\n<table width="100%" border="0" cellpadding="0" cellspacing="0" style="border-top: 1px solid #eee;">\n<tr><td style="padding: 24px 0 0;">\n<table width="100%" border="0" cellpadding="0" cellspacing="0" style="background-color: #f8fafc; border-radius: 8px; border: 1px solid #eef2f6;">\n<tr><td style="padding: 20px;">\n<p style="margin: 0 0 8px; color: #1E1E24; font-size: 14px; font-weight: 700; line-height: 1.3;">Noch Fragen?</p>\n<p style="margin: 0 0 14px; color: #666; font-size: 13px; line-height: 1.6;">Wir helfen Ihnen gerne bei allen Fragen rund um rentably und Ihren Start weiter.</p>\n<table border="0" cellpadding="0" cellspacing="0">\n<tr><td style="padding: 0 0 4px; color: #555; font-size: 13px; line-height: 1.5;">E-Mail: <a href="mailto:hallo@rentab.ly" style="color: #3c8af7; text-decoration: none; font-weight: 600;">hallo@rentab.ly</a></td></tr>\n<tr><td style="padding: 0; color: #555; font-size: 13px; line-height: 1.5;">WhatsApp: <a href="https://wa.me/493022334468" style="color: #3c8af7; text-decoration: none; font-weight: 600;">+49 30 2233 4468</a></td></tr>\n</table>\n<p style="margin: 8px 0 0; color: #999; font-size: 11px;">Mo &ndash; Fr, 9:00 &ndash; 18:00 Uhr</p>\n</td></tr>\n</table>\n</td></tr>\n</table>\n</td></tr>\n\n<!-- ============ SPACER ============ -->\n<tr><td style="padding: 8px 0 0;">&nbsp;</td></tr>\n\n<!-- ============ FOOTER (unchanged) ============ -->\n<tr><td style="padding: 20px 32px; border-top: 1px solid #eee; text-align: center;">\n<p style="margin: 0 0 4px; color: #999; font-size: 12px;">&copy; 2026 <a href="https://rentab.ly" style="color: #3c8af7; text-decoration: none;">rentably</a></p>\n<p style="margin: 0 0 8px; color: #bbb; font-size: 11px; line-height: 1.5;">Sie erhalten diese E-Mail, weil Sie als Nutzer bei rentably angemeldet sind.</p>\n<p style="margin: 0 0 6px; color: #bbb; font-size: 11px; line-height: 1.8;"><a href="mailto:hallo@rentab.ly" style="color: #3c8af7; text-decoration: none;">hallo@rentab.ly</a>&nbsp;&nbsp;|&nbsp;&nbsp;<a href="https://wa.me/493022334468" style="color: #3c8af7; text-decoration: none;">WhatsApp</a>&nbsp;&nbsp;|&nbsp;&nbsp;Mo &ndash; Fr, 9:00 &ndash; 18:00 Uhr</p>\n<p style="margin: 0; color: #bbb; font-size: 11px; line-height: 1.5;"><a href="https://rentab.ly/datenschutz" style="color: #3c8af7; text-decoration: none;">Datenschutz</a>&nbsp;|&nbsp;<a href="https://rentab.ly/impressum" style="color: #3c8af7; text-decoration: none;">Impressum</a>&nbsp;|&nbsp;<a href="https://rentab.ly/kontakt" style="color: #3c8af7; text-decoration: none;">Kontakt</a></p>\n</td></tr>\n\n</table>\n</td></tr>\n</table>\n</body>\n</html>';

v_text := E'Willkommen bei rentably\n\nHallo {{userName}},\n\nschoen, dass Sie hier sind. Ihr 30-taegiger Pro-Test ist jetzt aktiv -- Sie koennen ab sofort alle Funktionen nutzen. Damit der Einstieg leicht faellt, zeigen wir Ihnen die drei wichtigsten Schritte fuer den Start.\n\n\nWARUM LOHNT SICH DER EINSTIEG?\n-------------------------------\n- Kompletter Ueberblick -- Objekte, Einheiten und Mietvertraege an einem Ort\n- Mietkonten im Blick -- Zahlungseingaenge automatisch erfassen, kein manuelles Nachhalten mehr\n- Alles digital -- Dokumente, Kommunikation und Abrechnungen zentral und jederzeit abrufbar\n- Weniger Aufwand -- Betriebskostenabrechnungen in Minuten statt Stunden erstellen\n\n\nIHRE ERSTEN 3 SCHRITTE\n-----------------------\n\nSCHRITT 1: Objekt anlegen\nErstellen Sie Ihr erstes Objekt in rentably und hinterlegen Sie die wichtigsten Daten. So haben Sie immer einen vollstaendigen Ueberblick ueber Ihre Immobilien -- egal ob Mehrfamilienhaus, Eigentumswohnung oder Gewerbeeinheit.\n\nSo funktioniert es:\n1. Melden Sie sich bei rentably an\n2. Gehen Sie zu "Objekte" und klicken Sie auf "Objekt hinzufuegen"\n3. Waehlen Sie den Objekttyp und geben Sie die Adresse ein\n\n\nSCHRITT 2: Einheiten hinzufuegen\nNachdem Ihr Objekt angelegt ist, fuegen Sie die zugehoerigen Einheiten hinzu. Damit stellen Sie sicher, dass jeder Einheit spaeter ein Mietverhaeltnis und die richtigen Buchungen zugeordnet werden.\n\nWarum ist das wichtig?\n- Mietverhaeltnisse und Zahlungen korrekt zuordnen\n- Voraussetzung fuer die Nebenkostenabrechnung\n- Uebersicht ueber vermietete Einheiten und Leerstand\n\nWas ist eine Einheit?\nEine Einheit ist z.B. eine Wohnung, eine Garage / ein Stellplatz oder eine Gewerbeflaeche. Alles, was einen eigenen Mietvertrag erhaelt, kann eine Einheit sein. Beispiel: Ein Objekt mit 10 Wohnungen, 3 Stellplaetzen und einem Ladenlokal enthaelt insgesamt 14 Einheiten.\n\n\nSCHRITT 3: Mietverhaeltnis erfassen\nJetzt legen Sie Ihre Mietverhaeltnisse direkt in den passenden Einheiten an. So haben Sie Mietzahlungen, Vertraege und Mieterdaten vollstaendig und uebersichtlich an einem Ort.\n\nVorteile der digitalen Mietverwaltung:\n- Automatische Mietbuchungen und Zahlungserinnerungen\n- Mieterdaten und Dokumente zentral gespeichert\n- Uebersicht ueber alle aktiven Mietverhaeltnisse\n\n>> Jetzt loslegen: {{dashboard_link}}\n\n\nDAS SAGEN UNSERE NUTZER\n------------------------\n"Seit ich rentably nutze, habe ich endlich den Ueberblick ueber alle Mietverhaeltnisse. Die Betriebskostenabrechnung dauert keine Stunden mehr, sondern Minuten."\n-- Thomas M., Vermieter, 4 Wohnungen\n\n"Die Struktur mit Einheiten, Mietern und Vertraegen bildet unseren Arbeitsalltag perfekt ab. Endlich ein Tool, das fuer professionelle Verwalter gemacht ist."\n-- Markus F., Geschaeftsfuehrer, WEG-Verwaltung\n\n\nSCHNELL OBJEKTE & EINHEITEN IMPORTIEREN\n----------------------------------------\nJe schneller Ihre Daten in rentably hinterlegt sind, desto effizienter wird Ihre Verwaltung.\n\nTipp: Falls Sie bereits bestehende Daten haben, koennen Sie diese einfach per CSV- oder Excel-Upload importieren -- kein manuelles Eintippen noetig.\n\n\nIHRE CHECKLISTE FUER DEN START\n-------------------------------\n[x] Konto erstellt\n[ ] Erstes Objekt anlegen -- Grundlage fuer Ihr Immobilienmanagement\n[ ] Einheit anlegen -- Wohnung, Garage oder Gewerbe\n[ ] Mietverhaeltnis erfassen -- Ausgangspunkt fuer Ihre Mietverwaltung\n[ ] Bankkonto verknuepfen -- automatische Mieteingangskontrolle\n[ ] Finanzen auswerten -- Miet- und Objektberichte auf einen Blick\n[ ] Nebenkostenabrechnung erstellen -- mit nur wenigen Klicks\n[ ] Dokumente digital speichern -- kein Papierchaos mehr\n\n\nWaehrend Ihrer 30-taegigen Testphase nutzen Sie rentably im vollen Pro-Umfang und lernen alle Funktionen direkt in der Praxis kennen.\n\n>> Jetzt Verwaltung starten: {{dashboard_link}}\n\n\nNOCH FRAGEN?\nWir helfen Ihnen gerne bei allen Fragen rund um rentably und Ihren Start weiter.\nE-Mail: hallo@rentab.ly\nWhatsApp: +49 30 2233 4468\nMo - Fr, 9:00 - 18:00 Uhr\n\n\n--\nrentably | hallo@rentab.ly | WhatsApp: https://wa.me/493022334468\nMo - Fr, 9:00 - 18:00 Uhr\nDatenschutz: https://rentab.ly/datenschutz | Impressum: https://rentab.ly/impressum | Kontakt: https://rentab.ly/kontakt';

UPDATE email_templates
SET
  subject = 'Willkommen bei rentably – starten Sie jetzt mit Ihren ersten 3 Schritten',
  body_html = v_html,
  body_text = v_text,
  variables = '["userName", "dashboard_link", "user_email"]'::jsonb,
